mapper.select:
SELECT id
FROM hb_flow_run
WHERE tenant_id = #{tenantId}
  AND engine_instance_id = #{engineInstanceId}
ORDER BY id DESC LIMIT 1

SELECT COUNT(*) AS total_runs,
SUM(CASE WHEN status IN ('CREATED','RUNNING','PROCESSING') THEN 1 ELSE 0 END) AS running_runs,
SUM(CASE WHEN status = 'WAITING' THEN 1 ELSE 0 END) AS waiting_runs,
SUM(CASE WHEN status = 'SUCCESS' THEN 1 ELSE 0 END) AS success_runs,
SUM(CASE WHEN status IN ('FAILED','TIMEOUT') THEN 1 ELSE 0 END) AS failed_runs,
SUM(CASE WHEN status = 'CANCELED' THEN 1 ELSE 0 END) AS canceled_runs,
COALESCE(AVG(elapsed_ms), 0) AS average_duration_ms
FROM hb_flow_run
WHERE tenant_id = #{tenantId}
AND flow_id = #{flowId}
AND started_at >= #{startedAfter}
AND started_at <= #{startedBefore}

SELECT last_event_seq
FROM hb_flow_run
WHERE id = #{id}
  AND tenant_id = #{tenantId}
    FOR UPDATE

mapper.update:
